import{_ as t,o as a,c as e,a1 as i}from"./chunks/framework.BmLW0N4k.js";const m=JSON.parse('{"title":"序盤攻略・基本戦略","description":"","frontmatter":{},"headers":[],"relativePath":"guide/early-game-strategy.md","filePath":"guide/early-game-strategy.md"}'),n={name:"guide/early-game-strategy.md"};function l(o,r,s,g,h,d){return a(),e("div",null,[...r[0]||(r[0]=[i('<h1 id="序盤攻略・基本戦略" tabindex="-1">序盤攻略・基本戦略 <a class="header-anchor" href="#序盤攻略・基本戦略" aria-label="Permalink to &quot;序盤攻略・基本戦略&quot;">​</a></h1><blockquote><p>このページはインターネット上の攻略情報を集約した内容です。未検証の情報を含む場合があります。</p></blockquote><hr><h2 id="_1-ゲーム開始前の設定" tabindex="-1">1. ゲーム開始前の設定 <a class="header-anchor" href="#_1-ゲーム開始前の設定" aria-label="Permalink to &quot;1. ゲーム開始前の設定&quot;">​</a></h2><ul><li><strong>初プレイはキャンペーン推奨。</strong> 物語を通じて基本を順に学べます（チュートリアル代わり）。設定で「フルチュートリアル」を有効化するとより親切です。</li><li><strong>開始地域はラティウム（ローマ）を推奨。</strong> アルビオン（ケルト）より易しいです。</li><li>ロード直後に**一時停止（ポーズ）**して、資金を消費せずにレイアウトを計画しましょう。いきなり建設せず計画モードで検討するのがコツです。</li></ul><hr><h2 id="_2-序盤の建設順-基本の型" tabindex="-1">2. 序盤の建設順（基本の型） <a class="header-anchor" href="#_2-序盤の建設順-基本の型" aria-label="Permalink to &quot;2. 序盤の建設順（基本の型）&quot;">​</a></h2><ol><li><strong>道路を大量に敷く。</strong> すべての建物は道路で倉庫／交易所に接続しないと機能しません。</li><li><strong>木材生産チェーンを最優先で構築</strong>（→ 第3節）。</li><li><strong>交易所</strong>を生産施設の範囲内に配置。交易所を倉庫の代わりにして基盤にする。</li><li><strong>Tier1住民（リベルトゥス）の住居</strong>を市場の効果範囲内に並べ、基本需要を満たす。</li><li>収入が安定したら住居を増やし、満たせる範囲で段階的に拡張。</li></ol><hr><h2 id="_3-木材生産チェーン-最重要" tabindex="-1">3. 木材生産チェーン（最重要） <a class="header-anchor" href="#_3-木材生産チェーン-最重要" aria-label="Permalink to &quot;3. 木材生産チェーン（最重要）&quot;">​</a></h2><p>ほぼ全ての建物が<strong>木材</strong>を要求するため、これを最初に確保します。</p><ul><li><strong>木こり</strong>を森林密度の高い（理想は100%）場所に建て、<strong>製材所</strong>と1セットで丸太を木材へ加工します。最序盤（または入植直後）は交易所に近い場所に置き、倉庫建築分の木材が確保できたら移設しましょう。</li><li><strong>最低でも2系統用意するのを推奨</strong>（木材は枯渇しやすいボトルネック）。</li><li>効率比の目安: 木こり &amp; 製材所 = 各30秒（1:1の比率）</li><li>経済スキルツリーの「緑地の再生」があると平野に設置でき、森林密度が無視できるので効率的な配置が可能に。</li></ul><hr><h2 id="_4-倉庫の仕組み" tabindex="-1">4. 倉庫の仕組み <a class="header-anchor" href="#_4-倉庫の仕組み" aria-label="Permalink to &quot;4. 倉庫の仕組み&quot;">​</a></h2><ul><li>生産した商品は<strong>倉庫／交易所に保管</strong>され、使われるまでそこに在庫として残ります。</li><li><strong>全ての倉庫・交易所は相互接続。</strong> 1か所に入れた商品は全拠点で利用可能です。</li><li>生産者が原料を直接取りに行けるため、中間素材の受け渡しに倉庫は必須ではありません。ただし<strong>完成品を流通させるには倉庫が必要</strong>なため、完成品を扱う施設や住居の近くには倉庫を配置しましょう。</li></ul><hr><h2 id="_5-住民層と需要-tier1-リベルトゥス" tabindex="-1">5. 住民層と需要（Tier1: リベルトゥス） <a class="header-anchor" href="#_5-住民層と需要-tier1-リベルトゥス" aria-label="Permalink to &quot;5. 住民層と需要（Tier1: リベルトゥス）&quot;">​</a></h2><p>ラティウムは4階級（リベルトゥス → プレブス → エクィテス → パトリキ）。ゲーム開始はリベルトゥスからです。</p><p>リベルトゥスの基本3カテゴリ:</p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>イワシ（漁師小屋）、お粥（お粥の屋台）</td></tr><tr><td>公共サービス</td><td>市場、酒場</td></tr><tr><td>ファッション</td><td>チュニック、ピレウス帽</td></tr></tbody></table><ul><li><strong>オプショナル需要制:</strong> 同一カテゴリ内は全品目を揃えなくてよいです。<strong>各カテゴリを100％に</strong>満たせば昇格条件を満たせます。すべて満たせば200％。</li><li>上位層への昇格は「すべてのカテゴリーで100％以上を充足」が条件です。</li></ul><p>詳細な各層需要一覧は <a href="/wiki/population.html">住民層</a> を参照してください。</p><hr><h2 id="_6-経済・収入管理" tabindex="-1">6. 経済・収入管理 <a class="header-anchor" href="#_6-経済・収入管理" aria-label="Permalink to &quot;6. 経済・収入管理&quot;">​</a></h2><ul><li>主な支出は<strong>建物の維持費</strong>。「建設＋維持だけで資金が溶ける」ため、必要な建物のみ建てましょう。</li><li>基本の収入源は<strong>住民からの収入</strong>。需要を満たされた住民は収入を生みだします。支出＜収入の状態が維持できていれば住民をアップグレードさせていきます。早まってアップグレードさせると財政が破綻するので注意。</li><li>序盤は木材が不足がちですが、設計モードで配置を決定して随時建設していきましょう。公共施設（市場・酒場）を配置して要求を満たすことも忘れずに。</li><li>お粥は必須需要ですが建物効果はないため、無理に住居に隣接させる必要はありません。収入効果のある<strong>チュニック・ピレウス帽</strong>の建物エリア効果で収入アップさせる方が有益です（ただし倉庫範囲内かは要確認）。</li></ul><hr><h2 id="_7-都市レイアウト-基本・序盤" tabindex="-1">7. 都市レイアウト（基本・序盤） <a class="header-anchor" href="#_7-都市レイアウト-基本・序盤" aria-label="Permalink to &quot;7. 都市レイアウト（基本・序盤）&quot;">​</a></h2><ul><li><strong>基本思想:</strong> 市場など公共サービスをすべての住民に提供し、需要の充足と人口・収入・健康・幸福・火災安全度を維持する。</li><li><strong>住居を建てたら市場と酒場</strong>で全体をカバーできる配置を心がけましょう。</li><li>レイアウトは自由ですが、住居は<strong>2x3・2x4のブロック</strong>を組み合わせると管理がしやすいです。2x3は市場・酒場を隣接させたときにブロック化しやすい形です。</li></ul><hr><h2 id="_8-落とし穴・やってはいけないこと" tabindex="-1">8. 落とし穴・やってはいけないこと <a class="header-anchor" href="#_8-落とし穴・やってはいけないこと" aria-label="Permalink to &quot;8. 落とし穴・やってはいけないこと&quot;">​</a></h2><ul><li><strong>全住居を一斉昇格させない。</strong> Tier1（リベルトゥス）住居をTier2（プレブス）に上げるとTier1労働者が失われ、<strong>伐採・漁業など下位産業が崩壊</strong>します。必要な人材は各建物上部のアイコンで人数を確保してから住民をアップグレードしていきましょう。</li><li><strong>交易船による資源の持ち去りに注意。</strong> 交易船は母島から資源を勝手に運び出し、本拠地の建設を枯渇させます。交易所で<strong>最低在庫レベルを設定</strong>して防ぎましょう（例: 在庫50未満なら木材を積み込まない）。</li><li><strong>発火源・危険建物の配置。</strong> 炭焼き師等は周辺建物の健康・防火を下げるため住居から離しましょう。</li><li><strong>重要: プラス効果は重複しないがマイナス効果は重複する。</strong> 2軒併設してエリア効果が重なるとプラス効果は1倍（重複なし）、マイナス効果は2倍になります。</li></ul><hr><h2 id="_9-その他のシステム-序盤に知っておくと良い" tabindex="-1">9. その他のシステム（序盤に知っておくと良い） <a class="header-anchor" href="#_9-その他のシステム-序盤に知っておくと良い" aria-label="Permalink to &quot;9. その他のシステム（序盤に知っておくと良い）&quot;">​</a></h2><ul><li><strong>配置ボーナス:</strong> 糸紡ぎ師（チュニック生産者）は効果範囲内の全建物の収入を+1。酒場など幸福度建物は範囲内の建物数に応じてボーナスが得られます。</li><li><strong>健康・防災:</strong> 医院で健康、見張りで防火、衛兵詰所で幸福を改善。小範囲・低効果ですがトイレ・井戸・監視塔もあります。</li><li><strong>研究システム:</strong> 経済・市民・軍事・DLC灰の予言の4ツリー。知識は研究スピードを上昇させます。図書館やラテン語学校などの公共施設のエリア効果で上昇します。詳細は <a href="/wiki/techs.html">スキルツリー</a> を参照。</li><li><strong>宗教:</strong> 初心者は「ケレス信仰」（農業・肥沃度の女神）推奨。ケルヌンノス信仰もおすすめです。</li><li><strong>軍事:</strong> 海軍・陸軍とも市民から徴兵されます。維持に労働力が必要なため、兵力を急成長させると労働力不足になるので注意。労働力は他の島から調達することも可能です。</li><li><strong>拡張の本質:</strong> 上位Tierの需要を満たすためには別種の生産力を持つ島が必要になってきます（序盤ではサバ・樹脂・オリーブなど）。木材等を船に積んで新しい交易所を作りますが、入植には多額の資金と維持費が必要なため、財政に余裕ができてから検討しましょう。</li></ul><hr><h2 id="出典" tabindex="-1">出典 <a class="header-anchor" href="#出典" aria-label="Permalink to &quot;出典&quot;">​</a></h2><ul><li><a href="https://news.ubisoft.com/en-us/article/4fvALjiPTxYODChSgRb1Mk/anno-117-pax-romana-5-tips-for-getting-started" target="_blank" rel="noreferrer">Ubisoft News - 5 Tips For Getting Started</a></li><li><a href="https://www.anno-union.com/getting-started-in-anno-117-pax-romana/" target="_blank" rel="noreferrer">Anno Union - Getting started in Anno 117</a></li><li><a href="https://www.thegamer.com/anno-117-pax-romana-beginner-guide/" target="_blank" rel="noreferrer">TheGamer - Complete Beginner&#39;s Guide</a></li><li><a href="https://games.gg/anno-117-pax-romana/guides/anno-117-pax-romana-ultimate-beginners-guide/" target="_blank" rel="noreferrer">GamesGG - Ultimate Beginner&#39;s Guide</a></li><li><a href="https://gamerant.com/anno-117-pax-romana-beginner-tips-tricks-starter-guide-how-play/" target="_blank" rel="noreferrer">GameRant - Beginner Tips &amp; Tricks</a></li><li><a href="https://intoindiegames.com/walkthroughs/anno-117-pax-romana-beginners-guide/" target="_blank" rel="noreferrer">Into Indie Games - Beginner&#39;s Guide</a></li></ul>',37)])])}const c=t(n,[["render",l]]);export{m as __pageData,c as default};
